import{_ as e,o as l,c as a,a7 as d}from"./chunks/framework.C5fSpjcB.js";const o=JSON.parse('{"title":"混沌（Chaos）","description":"","frontmatter":{},"headers":[],"relativePath":"ja/realms/chaos.md","filePath":"ja/realms/chaos.md","lastUpdated":1775394001000}'),n={name:"ja/realms/chaos.md"};function r(i,t,s,g,x,y){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="混沌-chaos" tabindex="-1">混沌（Chaos） <a class="header-anchor" href="#混沌-chaos" aria-label="Permalink to &quot;混沌（Chaos）&quot;">​</a></h1><p><span class="realm-badge realm-chaos">混沌</span></p><p><strong>混沌</strong>はクトゥルフ神話における外なる神々の狂気をテーマとした界域です。銀鍵エネルギーの運用と反撃を中心に構築し、鍵令スキルで戦闘に参加します。</p><h2 id="テーマ・世界観" tabindex="-1">テーマ・世界観 <a class="header-anchor" href="#テーマ・世界観" aria-label="Permalink to &quot;テーマ・世界観&quot;">​</a></h2><p>混沌界域はナイアルラトホテプやアザトースに代表される外なる神々の影響を色濃く受けた領域です。覚醒体たちは狂気に呑まれながらも、その力を武器として振るいます。</p><h2 id="戦闘スタイル" tabindex="-1">戦闘スタイル <a class="header-anchor" href="#戦闘スタイル" aria-label="Permalink to &quot;戦闘スタイル&quot;">​</a></h2><ul><li><strong>死亡抵抗</strong> — チームに混沌覚醒体がいれば追加で100%死亡抵抗（免死1回）を獲得</li><li><strong>銀鍵共鳴</strong>（純混沌編成）— 毎ターン自動で銀鍵エネルギー250点蓄積。1ターンに鍵令を2回使用可能（2回目は他の解放済み鍵令から選択）</li><li><strong>高瞬間火力</strong> — バースト時のダメージ倍率が高い</li><li><strong>万能適応</strong> — v2.0以降、他界域との共生効果を持つ</li></ul><h2 id="界域共生効果-v2-0以降" tabindex="-1">界域共生効果（v2.0以降） <a class="header-anchor" href="#界域共生効果-v2-0以降" aria-label="Permalink to &quot;界域共生効果（v2.0以降）&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">パートナー界域</th><th style="text-align:left;">共生効果</th></tr></thead><tbody><tr><td style="text-align:center;"><span class="realm-badge realm-aequor">深海</span></td><td style="text-align:left;">混沌覚醒体が狂気爆発後、ターン終了時に追加触腕攻撃+深海覚醒体全員に10点狂気付与</td></tr><tr><td style="text-align:center;"><span class="realm-badge realm-caro">血肉</span></td><td style="text-align:left;">ターン終了時に混沌覚醒体1体につき最大HP2%を猩紅溶鉱炉に蓄積。混沌覚醒体の狂気爆発時に胚融合+25%</td></tr><tr><td style="text-align:center;"><span class="realm-badge realm-ultra">超維</span></td><td style="text-align:left;">戦闘開始時に混沌覚醒体1体につき最大HP+1%、全敵の最大HP-0.5%、全超維覚醒体の暴撃ダメージ+10%</td></tr></tbody></table><h2 id="混沌界域の覚醒体" tabindex="-1">混沌界域の覚醒体 <a class="header-anchor" href="#混沌界域の覚醒体" aria-label="Permalink to &quot;混沌界域の覚醒体&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">覚醒体名</th><th style="text-align:center;">レア</th><th style="text-align:center;">役割</th><th style="text-align:center;">Tier</th><th style="text-align:left;">入手</th></tr></thead><tbody><tr><td style="text-align:left;">艾尔瓦 (Alva)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">防御型</td><td style="text-align:center;">T0</td><td style="text-align:left;">常驻</td></tr><tr><td style="text-align:left;">朵尔 (Doll)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">攻撃型</td><td style="text-align:center;">T0</td><td style="text-align:left;">常驻</td></tr><tr><td style="text-align:left;">環行·拉蒙娜 (Ramona: Timeworn)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">攻撃型</td><td style="text-align:center;">T0</td><td style="text-align:left;">限定</td></tr><tr><td style="text-align:left;">24 (24)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">攻撃型</td><td style="text-align:center;">T0</td><td style="text-align:left;">限定</td></tr><tr><td style="text-align:left;">奥吉尔 (Ogier)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">支援型</td><td style="text-align:center;">T1</td><td style="text-align:left;">常驻</td></tr><tr><td style="text-align:left;">萝坦 (Lotan)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">防御型</td><td style="text-align:center;">T1</td><td style="text-align:left;">常驻</td></tr><tr><td style="text-align:left;">拉蒙娜 (Ramona)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">支援型</td><td style="text-align:center;">T1</td><td style="text-align:left;">常驻</td></tr><tr><td style="text-align:left;">莉莉 (Lily)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">防御型</td><td style="text-align:center;">T1</td><td style="text-align:left;">活動</td></tr><tr><td style="text-align:left;">淡墨 (Danmo)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">攻撃型</td><td style="text-align:center;">T1</td><td style="text-align:left;">限定</td></tr><tr><td style="text-align:left;">潘狄娅 (Pandya)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">副攻撃型</td><td style="text-align:center;">T2</td><td style="text-align:left;">常驻</td></tr><tr><td style="text-align:left;">诺缔拉 (Nodera)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">攻撃型</td><td style="text-align:center;">T2</td><td style="text-align:left;">常驻</td></tr><tr><td style="text-align:left;">伽伦 (Galen)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">副攻撃型</td><td style="text-align:center;">T3</td><td style="text-align:left;">常驻</td></tr><tr><td style="text-align:left;">宁菲亚 (Nymphia)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">支援型</td><td style="text-align:center;">T3</td><td style="text-align:left;">常驻</td></tr><tr><td style="text-align:left;">莱克 (Karen)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">支援型</td><td style="text-align:center;">—</td><td style="text-align:left;">活動</td></tr><tr><td style="text-align:left;">哈姆林 (Hameln)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">支援型</td><td style="text-align:center;">—</td><td style="text-align:left;">唤醒</td></tr><tr><td style="text-align:left;">塔薇 (Tawil)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">支援型</td><td style="text-align:center;">—</td><td style="text-align:left;">唤醒</td></tr><tr><td style="text-align:left;">熔毁·朵尔 (Doll: Inferno)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">支援型</td><td style="text-align:center;">—</td><td style="text-align:left;">限定</td></tr><tr><td style="text-align:left;">凯蒂古拉 (Kathigu-Ra)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">攻撃型</td><td style="text-align:center;">—</td><td style="text-align:left;">限定</td></tr><tr><td style="text-align:left;">茉夏 (Mouchette)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">攻撃型</td><td style="text-align:center;">—</td><td style="text-align:left;">限定</td></tr></tbody></table><h2 id="おすすめ編成" tabindex="-1">おすすめ編成 <a class="header-anchor" href="#おすすめ編成" aria-label="Permalink to &quot;おすすめ編成&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>混沌界域は死亡抵抗を活かした攻撃的なプレイが基本です。死亡抵抗があることを理解した上で積極的に死抗を売る戦術が有効です。新規プレイヤーは初始四小只（SR版）での開荒を推奨します。</p></div><h3 id="_24混沌ナショナルチーム" tabindex="-1">24混沌ナショナルチーム <a class="header-anchor" href="#_24混沌ナショナルチーム" aria-label="Permalink to &quot;24混沌ナショナルチーム&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">枠</th><th style="text-align:left;">キャラ</th><th style="text-align:left;">役割</th></tr></thead><tbody><tr><td style="text-align:center;">メインC</td><td style="text-align:left;">24</td><td style="text-align:left;">コアDPS</td></tr><tr><td style="text-align:center;">支援</td><td style="text-align:left;">拉蒙娜 (Ramona)</td><td style="text-align:left;">印カード/複製</td></tr><tr><td style="text-align:center;">支援</td><td style="text-align:left;">奥吉尔 (Ogier)</td><td style="text-align:left;">嘲諷/指名</td></tr><tr><td style="text-align:center;">防御</td><td style="text-align:left;">莉莉 (Lily)</td><td style="text-align:left;">回復</td></tr></tbody></table><h3 id="塔薇チーム" tabindex="-1">塔薇チーム <a class="header-anchor" href="#塔薇チーム" aria-label="Permalink to &quot;塔薇チーム&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">枠</th><th style="text-align:left;">キャラ</th><th style="text-align:left;">役割</th></tr></thead><tbody><tr><td style="text-align:center;">メインC</td><td style="text-align:left;">塔薇 (Tawil)</td><td style="text-align:left;">全界域カードプールから選択。超限後ダメージ+35%</td></tr><tr><td style="text-align:center;">支援</td><td style="text-align:left;">拉蒙娜 (Ramona)</td><td style="text-align:left;">超限サポート</td></tr><tr><td style="text-align:center;">副C</td><td style="text-align:left;">伽伦 (Galen)</td><td style="text-align:left;">超限サポート</td></tr><tr><td style="text-align:center;">支援</td><td style="text-align:left;">莱克 (Karen)</td><td style="text-align:left;">出力補助</td></tr></tbody></table><h2 id="関連ページ" tabindex="-1">関連ページ <a class="header-anchor" href="#関連ページ" aria-label="Permalink to &quot;関連ページ&quot;">​</a></h2><ul><li><a href="./">界域概要</a></li><li><a href="./aequor.html">深海（Aequor）</a></li><li><a href="./caro.html">血肉（Caro）</a></li><li><a href="./ultra.html">超維（Ultra）</a></li><li><a href="./../awakeners/team-building.html">編成ガイド</a></li></ul>',19)])])}const h=e(n,[["render",r]]);export{o as __pageData,h as default};
